<script setup lang="ts">
import { computed, ref } from "vue";

type Post = { id: number; author: string; avatar: string; time: string; title: string; text: string; image?: string; likes: number; comments: number; liked: boolean };

const sort = ref("推荐");
const toast = ref("");
const posts = ref<Post[]>([
  { id: 1, author: "工具大禹", avatar: "禹", time: "2小时前", title: "【交易简报VOL.28】散人、老板、搬砖党，这周该去哪？一篇指南讲清楚！", text: "一、统计周期2026年7月13日—2026年7月19日，阅读提示以下数据仅反映上周交易情况，存在一定参考价值。", image: "report", likes: 0, comments: 1, liked: false },
  { id: 2, author: "伊水之", avatar: "伊", time: "1天前", title: "朗振180合击", text: "元宝1比10或者1比5还能玩，1比1的比例，微氪连药都买不起。魔血石大就是五块…", image: "battle", likes: 8, comments: 3, liked: false },
  { id: 3, author: "传奇老玩家", avatar: "玩", time: "2天前", title: "新服开荒攻略：第一天如何快速追上大部队", text: "整理了一份适合散人的开服路线，欢迎大家补充。", likes: 16, comments: 6, liked: false },
]);

const visiblePosts = computed(() => sort.value === "最新" ? [...posts.value].reverse() : posts.value);
function notify(message: string) { toast.value = message; window.setTimeout(() => toast.value = "", 1800); }
function toggleLike(post: Post) { post.liked = !post.liked; post.likes += post.liked ? 1 : -1; }
function publish(type: string) { notify(`${type}功能即将开放，敬请期待`); }
function navigate(label: string) { if (label === "首页") window.location.hash = "#/"; else if (label === "任务") window.location.hash = "#/tasks"; else if (label === "游戏") window.location.hash = "#/games"; else if (label === "SVIP") window.location.hash = "#/vip"; else if (label !== "社区") notify(`「${label}」页面即将开放`); }
</script>

