    <aside class="sidebar">
      <div class="brand">game<span>盒子</span></div>
      <button v-for="item in [['⌂','首页'],['▷','直播'],['◒','社区'],['♧','美女'],['♙','赛事'],['◉','游戏'],['✓','任务'],['♛','会员'],['S','SVIP'],['↗','抽奖'],['证','通行证']]" :key="item[1]" class="nav-item" :class="{ active: item[1] === '社区' }" @click="navigate(item[1])"><b>{{ item[0] }}</b><span>{{ item[1] }}</span><i v-if="item[1] === '任务'">•</i></button>
      <button class="voice" @click="notify('语音开黑功能即将开放')">◉<span>语音开黑</span></button>
    </aside>
    <main class="page">
      <div class="content-grid">
        <section class="feed-column">
          <header class="community-banner"><div class="community-icon">▢<small>···</small></div><div><h1>综合交流</h1><p>183173帖子</p></div><strong>GGG</strong></header>
          <section class="feed-card"><div class="feed-heading"><h2>动态推荐</h2><div><button :class="{ selected: sort === '推荐' }" @click="sort = '推荐'">智能排序⌄</button><button :class="{ selected: sort === '最新' }" @click="sort = '最新'">最新</button></div></div>
            <div class="promo-row"><div class="promo promo-a">传奇再燃<small>获奖作品公示</small></div><div class="promo promo-b">征文活动<small>参与征文活动，最高100000元</small></div></div>
            <article v-for="post in visiblePosts" :key="post.id" class="post"><div class="post-author"><div class="avatar" :class="`avatar-${post.id}`">{{ post.avatar }}</div><div><strong>{{ post.author }}</strong><small>{{ post.time }}<em v-if="post.id === 2"> · 胡振180合击</em></small></div><button class="more">⋮</button></div><h3>{{ post.title }}</h3><p>{{ post.text }} <a>全文⌄</a></p><div v-if="post.image" class="post-image" :class="post.image"><span v-if="post.image === 'report'">交易简报</span><span v-else>战 · 热血争锋</span><small>▣ +5</small></div><footer><span>最新回复36分钟前</span><div><button @click="toggleLike(post)" :class="{ liked: post.liked }">♡ {{ post.likes }}</button><button @click="notify('评论功能即将开放')">◌ {{ post.comments }}</button><button @click="notify('分享链接已复制')">↗ 分享</button></div></footer></article>
          </section>
        </section>
        <aside class="right-column"><section class="publish-card"><h2>发布中心</h2><button @click="publish('反馈')"><span>提反馈<small>BUG问题意见</small></span><b>☁</b></button><button @click="publish('文章')"><span>写文章<small>报服·评测·玩法</small></span><b class="purple">▰</b></button></section><section class="channel-card"><h2>社区</h2><div class="channel-item"><div class="community-icon small">▢<small>···</small></div><div><strong>综合交流</strong><p>183173帖子</p></div></div></section></aside>
      </div>
    </main>
    <div v-if="toast" class="toast">{{ toast }}</div>
  </div>
</template>

